    48→      _processingTimer?.cancel();
    49→    });
    50→  }
    51→
    52→  void _setupProcessing() {
    53→    _processingTimer?.cancel();
    54→    _processingTimer = Timer.periodic(
    55→      const Duration(seconds: 30),
    56→      (_) => processQueue(),
    57→    );
    58→  }
    59→
    60→  /// Add an operation to the queue
    61→  Future<void> addOperation(QueueableOperation operation) async {
    62→    _pendingOperations.add(operation);
    63→    await _persistQueue();
    64→
    65→    // Try to process immediately if conditions are right
    66→    if (_canProcess(operation)) {
    67→      processQueue();
    68→    }
    69→  }
    70→
    71→  /// Process all operations in the queue that can be executed
    72→  Future<void> processQueue() async {
    73→    if (_isProcessing) return;
    74→    _isProcessing = true;
    75→
    76→    try {
    77→      final tokenManager = ref.read(tokenManagerProvider);
    78→      final isOnline = ref.read(connectivityNotifierProvider);
    79→
    80→      // Process operations in priority order
    81→      final operations = _pendingOperations.toList()
    82→        ..sort((a, b) => b.priority.compareTo(a.priority));
    83→
    84→      for (final operation in operations) {
    85→        if (!_canProcess(operation)) continue;
    86→
    87→        try {
    88→          await operation.execute();
    89→          _pendingOperations.remove(operation);
